#include<bits/stdc++.h>
using namespace std;
map<int, int>m;
int main()
{
//	freopen("transfer.in","r",stdin);
//	freopen("transfer.out","w",stdout);
	int n;
	cin >> n;
	int cnt = 0;
	int l = 0, r = 0;
	while(n--){
		int s,pri,t;
		cin >> s >> pri >> t;
		if(s == 0){//如果是地铁，必须付钱 
			cnt += pri;
			// cout << cnt << " 地铁" << endl;
			m[t] = pri;
		}else{
			int flag = 0;
			for(int i = max(1, t - 45); i < t; i++){
				if(m.count(i) && m[i] >= pri){//如果有这个时间的优惠卷并且可以用 
					flag = 1;//打上标记
					m[i] = 0;//不能使用 
					break;
				}
			}
			if(!flag){
				cnt += pri;//如果没有打上标记，那就要付钱 
				// cout << cnt << " 用不了消费券，公交" << endl;
			}

		}
	}
	cout << cnt;
}
